svg.script:
(() => {
  "use strict";
  const svg = document.getElementById("mini-stage");

  // ── confirmed 常量 ──
  const TILT_PIVOT = { x: 187, y: 252 };   // 歪头轴 = 母版系脖根（sleep-peek/alert 同款）
  const TUFT_GRAVITY = -32;                 // 呆毛重力下垂角（mini base pose 定稿）
  const BLUSH_BASE_OP = 0.9;
  const BLUSH_CENTERS = { "left-blush": { x: 92, y: 185 }, "right-blush": { x: 281, y: 185 } };
  // 挑眉 = 表情板 v1 surprised path（逐字）；neutral = 母版默认眉
  const BROW = {
    leftNeutral: "M127 116 C137 108 148 110 154 118",
    rightNeutral: "M247 116 C237 108 226 110 220 118",
    leftRaised: "M123 106 C134 96 151 98 160 109",
    rightRaised: "M251 106 C240 96 223 98 214 109"
  };
  // 开心嘴 = attention/happy 定稿 rig（task-complete-loop-v1 逐字搬运：opening clip > door clip > 三层 fill）
  const MOUTH = {
    cx: 187, cavityY: 205, lowerCavityY: 218,
    sideY: 200, bottomY: 219.5, halfW: 6, doorInset: 8.5, doorRound: 13,
    cavityW: 25, cavityH: 45, lowerCavityW: 13, lowerCavityH: 8,
    bottomPulse: 1.25, insetPulse: 1.1, halfPulse: 0.45, roundPulse: 0.75
  };

  // ── peek 可调参数（tuner state）──
  const state = {
    // 推出（sleep-peek 同款）
    ext: 51.8, speed: 0.7,
    handDelay: 0, handDur: 200, handEase: 0,
    trailWidth: 1.8, trailOpacity: 0.75, trailFade: 0.45,
    // 好奇表情
    reactDur: 0.35, tiltAngle: 10, browRaise: 1, mouthOpen: 0.5,
    doorInset: 4, doorRound: 14,
    tuftPerk: -14, glassBob: 5, blushBoost: 0.18, holdMicro: 1.2,
    tieSwayAmp: 2.5
  };
  let browSingle = false;
  let mouthProgress = 0, mouthPulseT = 0;

  const EASES = [
    { name: "easeOutQuad(host)", fn: (t) => t * (2 - t) },
    { name: "linear", fn: (t) => t }
  ];
  // 推出时间线（sleep-peek 同款）：贴边 1.2s → 推出 0.2s → 保持 2s → 缩回 0.2s
  const T_REST = 1.2, T_PUSH = 0.2, T_HOLD = 2.0, T_PULL = 0.2;
  const T_TOTAL = T_REST + T_PUSH + T_HOLD + T_PULL;
  const LOOP_MODE = /[?&]loop=1\b/.test(location.search);
  const HOST_HOLD_PHASE = T_REST + T_PUSH + T_HOLD / 2;
  const EDGE_BASE = 235;
  const hostEase = EASES[0].fn;

  // ── 工具 ──
  function clamp(v, a, b) { return Math.max(a, Math.min(b, v)); }
  function lerp(a, b, t) { return a + (b - a) * t; }
  function smooth01(v) { const t = clamp(v, 0, 1); return t * t * (3 - 2 * t); }
  function easeOutBack(v) { const t = clamp(v, 0, 1) - 1; return 1 + t * t * (2.70158 * t + 1.70158); }
  function fmt(v) { return String(parseFloat(Number(v).toFixed(2))); }
  function fmtFine(v) { return String(parseFloat(Number(v).toFixed(4))); }
  function el(tag, attrs) {
    const node = document.createElementNS("http://www.w3.org/2000/svg", tag);
    for (const k in attrs) if (attrs[k] !== null && attrs[k] !== undefined) node.setAttribute(k, String(attrs[k]));
    return node;
  }
  function setT(id, transform) {
    const node = svg.querySelector(`#${id}`);
    if (node) { if (transform) node.setAttribute("transform", transform); else node.removeAttribute("transform"); }
  }
  function lerpPathNumbers(from, to, t) {
    const a = (from.match(/-?\d*\.?\d+/g) || []).map(Number);
    const b = (to.match(/-?\d*\.?\d+/g) || []).map(Number);
    let i = 0;
    if (a.length !== b.length) return t < 1 ? from : to;
    return from.replace(/-?\d*\.?\d+/g, () => { const v = lerp(a[i], b[i], t); i += 1; return fmt(v); });
  }

  // ── 开心嘴 rig（attention/happy 定稿逐字搬运：opening clip > door clip > 三层 fill；W 线最上）──
  function installMouthRig() {
    const noseMouth = svg.querySelector("#nose-mouth");
    const nose = svg.querySelector("#nose-fill");
    const left = svg.querySelector("#mouth-left");
    const right = svg.querySelector("#mouth-right");
    if (!noseMouth || svg.querySelector("#mouth-interior-clipped")) return;
    let defs = svg.querySelector("defs");
    const openingClip = el("clipPath", { id: "peek-mouth-opening-clip", clipPathUnits: "userSpaceOnUse" });
    openingClip.appendChild(el("path", { id: "mouth-opening-clip-path" }));
    const doorClip = el("clipPath", { id: "peek-mouth-door-clip", clipPathUnits: "userSpaceOnUse" });
    doorClip.appendChild(el("path", { id: "mouth-door-clip-path" }));
    defs.appendChild(openingClip);
    defs.appendChild(doorClip);
    const interior = el("g", { id: "mouth-interior-clipped", "clip-path": "url(#peek-mouth-opening-clip)" });
    const door = el("g", { id: "mouth-door-clipped", "clip-path": "url(#peek-mouth-door-clip)" });
    door.appendChild(el("path", { id: "mouth-inner-shade", fill: "#5b221f", opacity: ".36" }));
    door.appendChild(el("path", { id: "mouth-cavity-fill", fill: "#8c2f2a" }));
    door.appendChild(el("path", { id: "mouth-lower-cavity-fill", fill: "#f58d86" }));
    interior.appendChild(door);
    const strokes = el("g", { id: "mouth-visible-strokes" });
    strokes.appendChild(left);
    strokes.appendChild(right);
    noseMouth.insertBefore(interior, nose.nextSibling);
    noseMouth.appendChild(strokes);
  }
  function mouthClipParams() {
    const pulse = clamp(mouthPulseT, 0, 1) * state.holdMicro;
    return {
      sideY: MOUTH.sideY,
      bottomY: MOUTH.bottomY + MOUTH.bottomPulse * pulse,
      halfW: MOUTH.halfW + MOUTH.halfPulse * pulse,
      doorInset: state.doorInset - MOUTH.insetPulse * pulse,
      doorRound: state.doorRound + MOUTH.roundPulse * pulse
    };
  }
  function mouthOpeningClipD() {
    const p = clamp(mouthProgress / 100, 0, 1);
    const cx = MOUTH.cx;
    const mouth = mouthClipParams();
    const sideY = mouth.sideY;
    if (p <= 0.01) {
      return [
        `M ${fmt(cx - 0.35)} ${fmt(sideY)}`,
        `C ${fmt(cx - 0.35)} ${fmt(sideY)} ${fmt(cx - 0.15)} ${fmt(sideY)} ${fmt(cx)} ${fmt(sideY)}`,
        `C ${fmt(cx + 0.15)} ${fmt(sideY)} ${fmt(cx + 0.35)} ${fmt(sideY)} ${fmt(cx + 0.35)} ${fmt(sideY)}`,
        `C ${fmt(cx + 0.35)} ${fmt(sideY + 0.15)} ${fmt(cx + 0.18)} ${fmt(sideY + 0.2)} ${fmt(cx)} ${fmt(sideY + 0.2)}`,
        `C ${fmt(cx - 0.18)} ${fmt(sideY + 0.2)} ${fmt(cx - 0.35)} ${fmt(sideY + 0.15)} ${fmt(cx - 0.35)} ${fmt(sideY)} Z`
      ].join(" ");
    }
    const dx = cx - 187;
    const topYShift = (sideY - 199) * 0.18;
    const tx = (x) => x + dx;
    const ty = (y) => y + topYShift;
    const fullBottomDrop = Math.max(0.15, mouth.bottomY - sideY);
    const bottomDrop = fullBottomDrop * p;
    const bottomY = sideY + bottomDrop;
    const bottomW = Math.max(6, mouth.halfW);
    return [
      `M ${fmt(tx(163))} ${fmt(ty(192))}`,
      `C ${fmt(tx(163))} ${fmt(ty(195))} ${fmt(tx(166))} ${fmt(ty(198))} ${fmt(tx(171))} ${fmt(ty(198))}`,
      `C ${fmt(tx(180))} ${fmt(ty(198))} ${fmt(tx(187))} ${fmt(ty(190))} ${fmt(tx(187))} ${fmt(ty(177))}`,
      `C ${fmt(tx(187))} ${fmt(ty(190))} ${fmt(tx(194))} ${fmt(ty(198))} ${fmt(tx(203))} ${fmt(ty(198))}`,
      `C ${fmt(tx(208))} ${fmt(ty(198))} ${fmt(tx(211))} ${fmt(ty(195))} ${fmt(tx(211))} ${fmt(ty(192))}`,
      `C ${fmt(tx(211))} ${fmt(bottomY - bottomDrop * 0.15)} ${fmt(cx + bottomW)} ${fmt(bottomY)} ${fmt(cx)} ${fmt(bottomY)}`,
      `C ${fmt(cx - bottomW)} ${fmt(bottomY)} ${fmt(tx(163))} ${fmt(bottomY - bottomDrop * 0.15)} ${fmt(tx(163))} ${fmt(ty(192))} Z`
    ].join(" ");
  }
  function mouthDoorClipD() {
    const mouth = mouthClipParams();
    const inset = clamp(mouth.doorInset, 0, 22);
    const cx = MOUTH.cx;
    const topY = 166, tailY = 292;
    const sideY = mouth.sideY;
    const bottomY = mouth.bottomY;
    const left = 163 + inset;
    const right = 211 - inset;
    const lowerLeft = Math.max(left, cx - Math.max(0.1, mouth.halfW));
    const lowerRight = Math.min(right, cx + Math.max(0.1, mouth.halfW));
    const round = clamp(mouth.doorRound || 0, 0, Math.max(0.1, bottomY - sideY));
    const curveStartY = clamp(bottomY - round, sideY, bottomY - 0.1);
    const sideHandleY = lerp(curveStartY, bottomY, 0.72);
    const bottomHandleY = bottomY - round * 0.15;
    if (round <= 0.01) {
      return [`M ${fmt(left)} ${fmt(topY)}`, `L ${fmt(right)} ${fmt(topY)}`, `L ${fmt(right)} ${fmt(tailY)}`, `L ${fmt(left)} ${fmt(tailY)} Z`].join(" ");
    }
    return [
      `M ${fmt(left)} ${fmt(topY)}`,
      `L ${fmt(right)} ${fmt(topY)}`,
      `L ${fmt(right)} ${fmt(curveStartY)}`,
      `C ${fmt(right)} ${fmt(sideHandleY)} ${fmt(lowerRight)} ${fmt(bottomHandleY)} ${fmt(lowerRight)} ${fmt(bottomY)}`,
      `L ${fmt(lowerRight)} ${fmt(tailY)}`,
      `L ${fmt(lowerLeft)} ${fmt(tailY)}`,
      `L ${fmt(lowerLeft)} ${fmt(bottomY)}`,
      `C ${fmt(lowerLeft)} ${fmt(bottomHandleY)} ${fmt(left)} ${fmt(sideHandleY)} ${fmt(left)} ${fmt(curveStartY)}`,
      `L ${fmt(left)} ${fmt(topY)} Z`
    ].join(" ");
  }
  function mouthCavityD() {
    const cx = MOUTH.cx, cy = MOUTH.cavityY, w = MOUTH.cavityW, h = MOUTH.cavityH;
    return [
      `M ${fmt(cx - w)} ${fmt(cy)}`,
      `C ${fmt(cx - w)} ${fmt(cy - h * 0.55)} ${fmt(cx + w)} ${fmt(cy - h * 0.55)} ${fmt(cx + w)} ${fmt(cy)}`,
      `C ${fmt(cx + w)} ${fmt(cy + h * 0.66)} ${fmt(cx - w)} ${fmt(cy + h * 0.66)} ${fmt(cx - w)} ${fmt(cy)} Z`
    ].join(" ");
  }
  function mouthLowerCavityD() {
    const p = clamp((mouthProgress - 18) / 82, 0, 1);
    const cx = MOUTH.cx, cy = MOUTH.lowerCavityY;
    const w = Math.max(0.1, MOUTH.lowerCavityW * p);
    const h = Math.max(0.1, MOUTH.lowerCavityH * p);
    const tail = 46 + Math.max(0.15, MOUTH.bottomY - MOUTH.sideY);
    return [
      `M ${fmt(cx - w)} ${fmt(cy)}`,
      `C ${fmt(cx - w * 0.82)} ${fmt(cy - h)} ${fmt(cx + w * 0.82)} ${fmt(cy - h)} ${fmt(cx + w)} ${fmt(cy)}`,
      `L ${fmt(cx + w * 1.28)} ${fmt(cy + tail)}`,
      `L ${fmt(cx - w * 1.28)} ${fmt(cy + tail)} Z`
    ].join(" ");
  }
  function applyMouthPose() {
    const interior = svg.querySelector("#mouth-interior-clipped");
    const setAttr = (id, k, v) => { const n = svg.querySelector(`#${id}`); if (n) n.setAttribute(k, v); };
    setAttr("mouth-opening-clip-path", "d", mouthOpeningClipD());
    setAttr("mouth-door-clip-path", "d", mouthDoorClipD());
    setAttr("mouth-inner-shade", "d", mouthCavityD());
    setAttr("mouth-cavity-fill", "d", mouthCavityD());
    setAttr("mouth-lower-cavity-fill", "d", mouthLowerCavityD());
    if (interior) {
      interior.style.display = mouthProgress > 1 ? "" : "none";
      interior.setAttribute("opacity", fmt(0.72 + 0.28 * clamp(mouthProgress / 100, 0, 1)));
    }
  }

  // ── 腮红被逗到（淡显）：boost 0..1 → opacity 微增 + 绕中心轻微放大 ──
  function applyBlush(boost) {
    Object.keys(BLUSH_CENTERS).forEach((id) => {
      const node = svg.querySelector(`#${id}`);
      if (!node) return;
      node.setAttribute("opacity", fmt(clamp(BLUSH_BASE_OP + boost * 0.08, 0, 1)));
      const c = BLUSH_CENTERS[id];
      const s = 1 + boost * 0.55;
      setT(id, boost > .01 ? `translate(${fmt(c.x * (1 - s))} ${fmt(c.y * (1 - s))}) scale(${fmt(s)})` : "");
    });
  }

  // ── 推出时间线（sleep-peek 同款）：返回 edgeP / handP（0=贴边,1=推出 ext）+ phase + pushSince ──
  function peekAt(tSec) {
    const fz = document.getElementById("freeze-hold");
    const freeze = !LOOP_MODE || (fz ? fz.checked : false);
    const p = freeze ? HOST_HOLD_PHASE : (tSec % T_TOTAL);
    const handEase = EASES[state.handEase].fn;
    const dly = state.handDelay / 1000, dur = Math.max(.01, state.handDur / 1000);
    let edgeP, handP, pushSince = -1;
    if (p < T_REST) {
      edgeP = 0; handP = 0;
    } else if (p < T_REST + T_PUSH + T_HOLD) {
      const since = p - T_REST;
      edgeP = hostEase(clamp(since / T_PUSH, 0, 1));
      handP = handEase(clamp((since - dly) / dur, 0, 1));
      pushSince = since;
    } else {
      const since = p - T_REST - T_PUSH - T_HOLD;
      edgeP = 1 - hostEase(clamp(since / T_PULL, 0, 1));
      handP = 1 - handEase(clamp((since - dly) / dur, 0, 1));
    }
    return { edgeP, handP, phase: p, pushSince };
  }

  // ── 好奇表情进度：rest=0 → push 后 reactDur 内 easeOutBack ramp → hold 满 → pull 收回 ──
  function exprAt(phase) {
    if (phase < T_REST) return 0;
    if (phase < T_REST + T_PUSH + T_HOLD) {
      const since = phase - T_REST;
      return easeOutBack(clamp(since / state.reactDur, 0, 1));
    }
    const sincePull = phase - T_REST - T_PUSH - T_HOLD;
    return 1 - hostEase(clamp(sincePull / T_PULL, 0, 1));
  }

  // ── 每帧 ──
  let t0 = performance.now();
  function frame(now) {
    const t = (now - t0) / 1000 * state.speed;
    const pk = peekAt(t);
    const { edgeP, handP } = pk;

    // ① 推出模拟：边 + 遮罩（sleep-peek 逐字）
    const edgeX = EDGE_BASE + state.ext * edgeP;
    const mask = document.getElementById("edge-mask");
    const line = document.getElementById("edge-line");
    const text = document.getElementById("edge-text");
    if (mask) { mask.setAttribute("x", fmt(edgeX)); mask.setAttribute("width", fmt(430 - edgeX + 150)); }
    if (line) { line.setAttribute("x1", fmt(edgeX)); line.setAttribute("x2", fmt(edgeX)); }
    if (text) text.setAttribute("x", fmt(edgeX + 4));

    // ② 手随边平移（sleep-peek 逐字）：屏幕 x+ = 母版 y+，爪钉边纯平移，定稿串不碰
    const off = state.ext * handP;
    setT("peek-hands-ext", off > .01 ? `translate(0 ${fmt(off)})` : "");

    // ③ 手掌运动轨迹（sleep-peek 逐字）：推出时贴爪头出现、到位渐隐
    const dlyS = state.handDelay / 1000, durS = Math.max(.01, state.handDur / 1000);
    let trailAlpha = 0;
    if (pk.pushSince >= 0 && off > 0.5) {
      const settled = pk.pushSince - dlyS - durS;
      trailAlpha = settled <= 0 ? 1 : Math.max(0, 1 - settled / Math.max(.01, state.trailFade));
    }
    const trailA = trailAlpha * state.trailOpacity;
    ["trail-up-top", "trail-up-bottom", "trail-down-top", "trail-down-bottom"].forEach((id) => {
      const n = document.getElementById(id);
      if (!n) return;
      n.setAttribute("x1", "209");
      n.setAttribute("x2", fmt(209 + off));
      n.setAttribute("stroke-width", fmt(state.trailWidth));
      n.setAttribute("opacity", fmt(trailA));
    });

    // ④ 好奇表情（被推出来同步 ramp，pull 收回）
    const exprP = exprAt(pk.phase);
    const holdActive = pk.phase >= T_REST + T_PUSH && pk.phase < T_REST + T_PUSH + T_HOLD;
    const holdT = Math.max(0, pk.phase - T_REST - T_PUSH);
    const holdRamp = holdActive ? smooth01(holdT / 0.3) : 0;

    // 歪头：exprP 含 easeOutBack 过冲（被推歪一下回弹）+ 保持段呼吸微摆
    const microSway = Math.sin(2 * Math.PI * holdT / 2.6) * state.holdMicro * holdRamp;
    const tilt = state.tiltAngle * exprP + microSway;
    setT("peek-head-tilt", Math.abs(tilt) > .02 ? `rotate(${fmt(tilt)} ${TILT_PIVOT.x} ${TILT_PIVOT.y})` : "");

    // 挑眉：neutral → surprised raised；单挑只挑右眉
    const raise = clamp(exprP, 0, 1) * state.browRaise;
    const lb = svg.querySelector("#left-brow");
    const rb = svg.querySelector("#right-brow");
    if (lb) lb.setAttribute("d", lerpPathNumbers(BROW.leftNeutral, BROW.leftRaised, browSingle ? 0 : raise));
    if (rb) rb.setAttribute("d", lerpPathNumbers(BROW.rightNeutral, BROW.rightRaised, raise));

    // 开心小笑嘴：exprP 控开口 + 保持段脉动
    mouthProgress = state.mouthOpen * 100 * clamp(exprP, 0, 1);
    mouthPulseT = holdActive ? (0.5 + 0.5 * Math.sin(2 * Math.PI * holdT / 2.2)) * holdRamp : 0;
    applyMouthPose();

    // 呆毛：从重力垂(-32) 竖到 tuftPerk + 保持段轻飘（错相）
    const floatL = Math.sin(2 * Math.PI * 0.7 * holdT) * 2 * holdRamp;
    const floatR = Math.sin(2 * Math.PI * 0.7 * holdT + 0.9) * 2 * holdRamp;
    const tuftBase = lerp(TUFT_GRAVITY, state.tuftPerk, clamp(exprP, 0, 1));
    setT("left-tuft", `rotate(${fmt(tuftBase + floatL)} 182 49)`);
    setT("right-tuft", `rotate(${fmt(tuftBase + floatR)} 200 50)`);

    // 墨镜被推惯性晃：push 起阻尼振荡，约 0.7s 衰减归位
    const bob = pk.pushSince >= 0
      ? -state.glassBob * Math.sin(2 * Math.PI * 2.4 * pk.pushSince) * Math.exp(-pk.pushSince * 3.0)
      : 0;
    setT("peek-glasses-bob", Math.abs(bob) > .02 ? `translate(0 ${fmt(bob)})` : "");

    // 腮红被逗到
    applyBlush(clamp(exprP, 0, 1) * state.blushBoost);

    // 领带下摆：被推那下惯性甩（阻尼振荡，软部件被推反应，幅度比 hold 大）+ 保持段轻摆
    const tiePush = pk.pushSince >= 0
      ? state.tieSwayAmp * 2.4 * Math.sin(2 * Math.PI * 1.7 * pk.pushSince) * Math.exp(-pk.pushSince * 2.0)
      : 0;
    const tieHold = Math.sin(2 * Math.PI * holdT / 2.6 + 0.5) * state.tieSwayAmp * holdRamp;
    const tieSway = tiePush + tieHold;
    setT("tie-blade-sway", Math.abs(tieSway) > .02 ? `rotate(${fmt(tieSway)} 33.5 19)` : "");

    refreshJson();
    requestAnimationFrame(frame);
  }

  function refreshJson() {} // 面板已剥离(导出无 tuner)

  installMouthRig();
  requestAnimationFrame(frame);
  window.__miniPeek = { state, setBrowSingle: (v) => { browSingle = !!v; }, peekAt, exprAt, T: { T_REST, T_PUSH, T_HOLD, T_PULL, T_TOTAL } };
})();
